SELECT u.uid, u.uname, u.path, u.phone, u.career, u.address, u.verified, u.score
FROM user u
INNER JOIN follow f ON u.uid = f.follow_uid
WHERE f.uid = #{uid}
ORDER BY f.followtime DESC
LIMIT #{startPage}, #{pageSize}

SELECT COUNT(*)
FROM follow f
WHERE f.uid = #{uid}

